INSERT INTO public.photos VALUES (23740, 'Barrio de Roche 1927', 'Imagen capturada en el barrio de Roche, resultante de la parcelaciâ”śâ”‚n a principios de los aâ”śâ–’os 20 del campo de Juan Roche sito en una perifâ”śÂ®rica ubicaciâ”śâ”‚n entre la carretera de Valencia, la estaciâ”śâ”‚n de Cariâ”śâ–’ena y los talleres de Material Mâ”śâ”‚vil y Construcciones (hacia el fondo). La de la imagen se trataba probablemente de la parcela ya construida y con el numeral 13 de este barrio particular de una sola calle. Tras el 18 de julio de 1936 la calle serâ”śÂˇa redenominada de Desiderio Escosura. Actualmente esta localizaciâ”śâ”‚n se corresponderâ”śÂˇa con el punto donde la calle del Obispo Tajâ”śâ”‚n cruza la de Escosura.', 1927, 1927, 1927, 'Anos 20', 'DELICIAS', 41.64769500, -0.89843200, '0101000020E610000083C13577F4BFECBF306475ABE7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52324354983.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52324354983.webp', 'https://www.flickr.com/photos/zaragozaantigua/52324354983/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24030, 'Calle Duquesa Villahermosa 2003', 'Foto: Beatriz Benedicto. Entorno conocido como "Esquinas del Psiquiâ”śĂ­trico", con la calle de la Duquesa de Villahermosa en el centro, atravesâ”śĂ­ndolo de izquierda a derecha. Allâ”śÂˇ estâ”śĂ­n situadas las ferias del barrio de las Delicias. Entre 2007 y 2011, el entorno se urbanizarâ”śĂ­ con equipamientos pâ”śâ•‘blicos y viviendas. Al fondo a la derecha, Vâ”śÂˇa Universitas. Fuente: www.facebook.com/photo.php?fbid=532016703802554&set=g...', 2003, 2003, 2003, 'Siglo XXI', 'DELICIAS', 41.64665700, -0.90708000, '0101000020E6100000BB61DBA2CC06EDBF5F5D15A8C5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26208873619.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26208873619.webp', 'https://www.flickr.com/photos/zaragozaantigua/26208873619/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24217, 'Campo Sepulcro 1949', 'Imagen capturada en la factorâ”śÂˇa de Material Mâ”śâ”‚vil y Construcciones sita junto a la estaciâ”śâ”‚n de Campo Sepulcro y centrada en la armadura interior de uno de los diez automotores basados en el modelo Renault ABJ-4 encargados por RENFE, que una vez finalizados recibirâ”śÂˇan la denominaciâ”śâ”‚n de ABJ-7 dentro de la serie RENFE 9313-9332. Al fondo, vista parcial del barrio de Cariâ”śâ–’ena o de la Romareda con algunos de los singulares "hotelitos" vertebrados en torno a la calle del Moncayo. A la izquierda despunta una de las torrecillas de la antigua fâ”śĂ­brica de chocolates Orâ”śâ•‘s entonces ocupada por la sociedad Industrias del Cartonaje S.A.', 1949, 1949, 1949, 'Anos 40', 'DELICIAS', 41.64993900, -0.89733800, '0101000020E610000054A86E2EFEB6ECBF8EB27E3331D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54726346345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54726346345.webp', 'https://www.flickr.com/photos/zaragozaantigua/54726346345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25916, 'Duquesa Villahermosa 1969', 'Imagen de la unidad nâ”¬â•‘ 74 (un BUT de dos pisos) de la lâ”śÂˇnea de trolebuses "Ciudad Jardâ”śÂˇn", avanzando por la calle Duquesa Villahermosa hacia el emboque con la calle Pedro Lâ”śâ”‚pez de Luna, donde iniciar el retorno hacia la plaza de Santa Engracia. La imagen ha sido capturada, casualmente, en la esquina de la calle Don Pedro de Luna. Al fondo, a la izquierda, el gran bloque esquinero con la calle Luis Franco y Lâ”śâ”‚pez. A la derecha, arbolado de la "Ciudad Jardâ”śÂˇn" y, emergente, grâ”śâ•‘a de obra, posiblemente del nuevo bloque del nâ”¬â•‘ 30 de la calle de Luis Franco y Lâ”śâ”‚pez. Fuente visual: desequilibros.blogspot.com.es/', 1969, 1969, 1969, 'Anos 60', 'DELICIAS', 41.64802500, -0.90309800, '0101000020E610000000A8E2C62DE6ECBFC5FEB27BF2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30512970254.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30512970254.webp', 'https://www.flickr.com/photos/zaragozaantigua/30512970254/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25967, 'Huerta del Manicomio 1971', 'En 1873 la DPZ acordâ”śâ”‚ construir un Manicomio Modelo en la Granja de Ntra. Sra. del Pilar, en el Terminillo. Las obras comenzaron en 1878, pero muchos asilados continuaban ingresados en el antiguo Hospital de Gracia. En 1912 el Manicomio pasâ”śâ”‚ a depender del Estado. Una vez terminados, los pabellones tenâ”śÂˇan capacidad para 600 enfermos, y hasta 4 hectâ”śĂ­reas de buena huerta. El Plan Larrodera (1968) recalificâ”śâ”‚ parte de las zonas verdes para ladrillo, pero la presiâ”śâ”‚n ejercida durante aâ”śâ–’os de movilizaciones, encabezada por las Asociaciones de cabezas de Familia del barrio, consiguieron modificar el Plan, y terreno para el desdoblamiento de Vâ”śÂˇa Universitas y Duquesa Villahermosa, y para crear un nuevo Parque. En la imagen, parte de las huertas del Manicomio, la mâ”śĂ­s cercana a Duquesa Villahermosa y al Grupo de Viviendas "Severino Aznar" (derecha). En el centro, el Colegio Pâ”śâ•‘blico "Josâ”śÂ® Marâ”śÂˇa Mir". A su izquierda, el bloque de viviendas de la calle Santa Rita de Casia, en la actualidad vecino al CDM "Duquesa Villahermosa". Con la prolongaciâ”śâ”‚n de Duquesa de Villahermosa y el paso de la Vâ”śÂˇa Universitas, esta zona ha vivido una autâ”śÂ®ntica mutaciâ”śâ”‚n. Fuente visual: "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 1971, 1971, 1971, 'Anos 70', 'DELICIAS', 41.64673200, -0.90666100, '0101000020E610000083E0F1ED5D03EDBF6AA33A1DC8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14794570428.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14794570428.webp', 'https://www.flickr.com/photos/zaragozaantigua/14794570428/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25973, 'Ciudad Jardâ”śÂˇn c.1945', 'AHPZ. Estudio Coyne. Aâ”śâ–’os 40. "Ciudad jardâ”śÂˇn." Imagen tomada desde cierta altura en la calle Duquesa de Villahermosa, esquina calle Delicias. La que se abre a la izquierda (Lorenzo Calvo de Rozas) es una de las calles interiores de la barriada. Al fondo, la ciudad. Construida entre 1936-39, segâ”śâ•‘n proyecto de Miguel â”śĂĽngel Navarro. Ideadas dentro de la filosofâ”śÂˇa de construcciâ”śâ”‚n de "Casas Baratas", el franquismo reorientâ”śâ”‚ su adjudicaciâ”śâ”‚n, en positivo, hacia gentes leales al nuevo râ”śÂ®gimen, y en negativo hacia quienes no.', 1945, 1945, 1945, 'Anos 40', 'DELICIAS', 41.64781500, -0.90343200, '0101000020E6100000AC1DC539EAE8ECBFDB6D179AEBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15114921416.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15114921416.webp', 'https://www.flickr.com/photos/zaragozaantigua/15114921416/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25999, 'La Bozada 1991', 'Foto: Archivo Taumar (Irene Taulâ”śÂ®s y Rafael Margalâ”śÂ®). Vista aâ”śÂ®rea del barrio de la Bozada, con el IES Jerâ”śâ”‚nimo Zurita a la derecha, el parque Avempace en el centro y la Vâ”śÂ»a Univâ”śÂ®rsitas arriba. En la esquina superior derecha, el Hospital Clâ”śÂˇnico. Fuente: www.facebook.com/photo.php?fbid=1687674314789601&set=...', 1991, 1991, 1991, 'Anos 90', 'DELICIAS', 41.64414800, -0.90849800, '0101000020E6100000B267CF656A12EDBF54E4107173D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21785689684.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21785689684.webp', 'https://www.flickr.com/photos/zaragozaantigua/21785689684/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21567, 'Calle de Alfonso I c.1920', 'En 1918, Celestino Salinero Ena ampliâ”śâ”‚ y reformâ”śâ”‚ los originales "Grandes talleres de confecciâ”śâ”‚n La Casa Blanca" (Alfonso I, 22). La ampliaciâ”śâ”‚n incorporâ”śâ”‚ la planta calle del nâ”¬â•‘ 24 de la finca, chaflanero con la calle Miguel Molino. La reforma le confiriâ”śâ”‚ una nueva fachada de conjunto, con el caracterâ”śÂˇstico color blanco como seâ”śâ–’a de identidad, y unos interiores tambiâ”śÂ®n redecorados. En la imagen, la nueva fachada comercial. A la izquierda, la calle Miguel Molino. Fuente visual: aportaciâ”śâ”‚n de Mariano Lacruz Pâ”śÂ®rez de una reproducciâ”śâ”‚n fotogrâ”śĂ­fica realizada por Mariano Lacruz Berdejo sobre una imagen original cedida por Marâ”śÂˇa Josâ”śÂ® Salinero (nieta de Celestino Salinero).', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65471900, -0.88031000, '0101000020E6100000B3EF8AE07F2BECBFF0880AD5CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23243939405.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23243939405.webp', 'https://www.flickr.com/photos/zaragozaantigua/23243939405/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21568, '&quot;La Casa Blanca&quot; c.1920', 'Imagen de los "Grandes talleres de confecciâ”śâ”‚n La Casa Blanca" (Alfonso I, 22-24), de Celestino Salinero Ena, tras la reforma y ampliaciâ”śâ”‚n de 1918, con un curioso y considerable trampantojo en forma de dibujo que integra toda la primera planta de la finca en el comercio (la parte real era la del fondo, recayente a la calle de Goya, ademâ”śĂ­s de toda la planta calle). El chaflâ”śĂ­n de primer plano de la imagen, el real (planta calle) y el dibujado (primera planta), en el arranque de la calle Miguel Molino. En la parte superior, cartel indicativo del Hotel de Elâ”śÂˇas Cequiel establecido en este inmueble del nâ”¬â•‘ 24 de la calle de Alfonso I y del nâ”¬â•‘ 2 de la calle de Miguel Molino. Fuente visual: aportaciâ”śâ”‚n de Mariano Lacruz Pâ”śÂ®rez de una reproducciâ”śâ”‚n fotogrâ”śĂ­fica realizada por Mariano Lacruz Berdejo sobre una imagen original cedida por Marâ”śÂˇa Josâ”śÂ® Salinero (nieta de Celestino Salinero).', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65471900, -0.88031000, '0101000020E6100000B3EF8AE07F2BECBFF0880AD5CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23246383025.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23246383025.webp', 'https://www.flickr.com/photos/zaragozaantigua/23246383025/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21671, 'Calle de Alfonso I aâ”śâ–’os 30', 'Aâ”śâ–’os 30 del siglo XX. Colecciâ”śâ”‚n Vâ”śÂˇctor Barâ”śâ”‚n. Fila de mujeres para comprar en "Las nuevas sederâ”śÂˇas". El portal de vecinos entre esa tienda y el Bazar es el nâ”śâ•‘mero 26 de la calle, donde vive Dolores Serrat, consejera de Educaciâ”śâ”‚n del Gobierno de Aragâ”śâ”‚n entre 2011 y 2015 y miembro del Partido Popular. El dato es vox pâ”śâ”‚puli porque las manifestaciones ciudadanas recorrâ”śÂˇan obligadas otros itinerarios para no molestarla; ademâ”śĂ­s de que allâ”śÂˇ mismo el profesor Antonio Aramayona se colocaba a protestar diariamente desde junio de 2013 por la polâ”śÂˇtica de Educaciâ”śâ”‚n de la DGA.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65505700, -0.88009600, '0101000020E6100000B0E42A16BF29ECBF080264E8D8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14760231379.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14760231379.webp', 'https://www.flickr.com/photos/zaragozaantigua/14760231379/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21881, 'Calle de Alfonso I 1931', 'Imagen capturada en la calle de Alfonso I en el punto donde desde la izquierda desemboca la calle de la Manifestaciâ”śâ”‚n, y donde hacia la derecha comienza la calle de Espoz y Mina. Hacia el fondo, manzanas finales del tramo hasta la plaza del Pilar, que al fondo presenta su antigua y despejada fachada, mâ”śĂ­s visible por la realizaciâ”śâ”‚n de la foto en â”śÂ®poca invernal, como ilustran los â”śĂ­rboles de la plaza. Entre los bajos comerciales entoldados a la izquierda, la tienda de tejidos de Pascual Blasco D''Harcourt. En la umbrâ”śÂˇa derecha, guanterâ”śÂˇa La Catalana.', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65545500, -0.87982800, '0101000020E6100000E25CC30C8D27ECBFF67F0EF3E5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47569597722.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47569597722.webp', 'https://www.flickr.com/photos/zaragozaantigua/47569597722/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21987, 'Calle de Alfonso I 1949', 'Acuarela incluida en la serie "Rincones de Espaâ”śâ–’a", publicada en 1953 por los laboratorios Roche de Madrid, que reproduce la calle de Alfonso I, con el Pilar al fondo. Fuente: www.delcampe.net', 1949, 1949, 1949, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.65517900, -0.88009900, '0101000020E6100000F4C0C760C529ECBF5303CDE7DCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30241943843.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30241943843.webp', 'https://www.flickr.com/photos/zaragozaantigua/30241943843/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22392, 'Calle Olmo 1965', 'Calle del Olmo. Al fondo, la calle del Temple. Fuente visual: Foto Leonardo Pâ”śÂ®rez Obis, donada por â”śĂĽngel Hernâ”śĂ­ndez Mostajo para www.rafaelcastillejo.com', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65553400, -0.88188900, '0101000020E6100000F777B6476F38ECBF42B5C189E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22750235347.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22750235347.webp', 'https://www.flickr.com/photos/zaragozaantigua/22750235347/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23287, 'Calle de Alfonso I 1909', 'Imagen de la calle Alfonso I enfocando en direcciâ”śâ”‚n hacia el Coso Alto. La calle de la izquierda es la de Espoz y Mina. La de la derecha, Manifestaciâ”śâ”‚n. Al fondo, fachada del palacio del marquâ”śÂ®s de Campo Franco, que pocos aâ”śâ–’os despuâ”śÂ®s serâ”śĂ­ piqueteado para dar paso al edificio del Banco de Aragâ”śâ”‚n, obra de Manuel del Busto (1913). Fuente: Instituto Amatller de Arte Hispâ”śĂ­nico (Arxiu Mas).', 1909, 1909, 1909, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65555100, -0.87971000, '0101000020E610000066DAFE959526ECBF18EE5C18E9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15700543099.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15700543099.webp', 'https://www.flickr.com/photos/zaragozaantigua/15700543099/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23291, 'Calle de Alfonso I 1908', 'Vista de la calle de Alfonso I, desde el cruce con las calles Contamina (izquierda), y Goya (derecha). Antes de la instalaciâ”śâ”‚n del local comercial "La Casa Blanca".', 1908, 1908, 1908, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65545300, -0.87984000, '0101000020E6100000F2CD3637A627ECBF558847E2E5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20364430090.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20364430090.webp', 'https://www.flickr.com/photos/zaragozaantigua/20364430090/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23295, 'Calle Manifestaciâ”śâ”‚n c.1895', 'Luminosa imagen finisecular capturada desde el primer piso del 82 de la calle Manifestaciâ”śâ”‚n (actual 40), hacia el punto de cruce entre esta calle, y la de Alfonso I, por donde transita hacia la plaza del Pilar una humana procesionaria. En los bajos del 89-91 (actual 35), el "Comercio de Valero Palomar". Al otro lado de la calle Alfonso I, arranca hacia la izquierda el callejâ”śâ”‚n de la Leche, y hacia la derecha los primeros edificios impares de la calle Espoz y Mina, que no es que parezca estrecharse: es que lo hace. En los aâ”śâ–’os 20 del siglo XX, la Leche serâ”śĂ­ redenominada "Fray Juan Cebriâ”śĂ­n". Fuente: donaciâ”śâ”‚n de Luis Gâ”śâ”‚mez Laguna, Archivo Pâ”śâ•‘blico Municipal.', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65545300, -0.87984000, '0101000020E6100000F2CD3637A627ECBF558847E2E5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22622105418.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22622105418.webp', 'https://www.flickr.com/photos/zaragozaantigua/22622105418/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23299, 'Calle de Alfonso I c.1910', 'En 1908, el ayerbense Celestino Salinero Ena visitâ”śâ”‚ la ciudad de Parâ”śÂˇs, y quedâ”śâ”‚ impresionado por el comercio denominado "La Maison Blanche", especializado en la venta de ropa "blanca". A la vuelta, mientras Zaragoza celebraba el Centenario I de los "Sitios", Celestino se embarcâ”śâ”‚ en la aventura de reproducir en la ciudad lo visto en Parâ”śÂˇs. Asâ”śÂˇ, en la calle Alfonso I nâ”¬â•‘ 22 (local y primera planta), junto a la entrada de la calle Goya, fundâ”śâ”‚ "La Casa Blanca", unos innovadores y exitosos "grandes" talleres de confecciâ”śâ”‚n y venta directa de gâ”śÂ®neros de punto, juegos de cama, cubierta, toallas, mantelerâ”śÂˇas... De la ciudad de la luz se trajo, tambiâ”śÂ®n, la francesa idea de iluminar el comercio con lâ”śĂ­mparas de gas, siendo pionero en Zaragoza. En la imagen, Celestino Salinero Ena posando ante su empresa vital. Fuente visual: aportaciâ”śâ”‚n de Mariano Lacruz Pâ”śÂ®rez de una reproducciâ”śâ”‚n fotogrâ”śĂ­fica realizada por Mariano Lacruz Berdejo sobre una imagen original cedida por Marâ”śÂˇa Josâ”śÂ® Salinero (nieta de Celestino Salinero).', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”śĂ´RICO', 41.65471900, -0.88031000, '0101000020E6100000B3EF8AE07F2BECBFF0880AD5CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23242807685.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23242807685.webp', 'https://www.flickr.com/photos/zaragozaantigua/23242807685/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23315, 'Calle de Alfonso I 1908', 'Imagen capturada en la calle de Alfonso I durante la visita del rey Alfonso XIII el dâ”śÂˇa 15 de junio de ese aâ”śâ–’o a diversos eventos relacionados con el primer centenario del asedio francâ”śÂ®s de 1808. En este caso se trata de la "procesiâ”śâ”‚n câ”śÂˇvico-religiosa" que acompaâ”śâ–’aba los fâ”śÂ®retros de las heroâ”śÂˇnas Casta â”śĂĽlvarez, Manuela Sancho y Agustina Zaragoza desde el templo del Pilar y hasta la iglesia del Portillo, donde fueron inhumadas. La instantâ”śĂ­nea, realizada a la altura del nâ”¬â•‘ 28 de la calle, junto al emboque a la calle de Espoz y Mina donde destaca al fondo el depâ”śâ”‚sito de transparentes de "La Veneciana", recoge el paso del cortejo en torno al rey Alfonso XIII flanqueado por los infantes Luis Alfonso y Luis Fernando, precedido por el marquâ”śÂ®s de Viana y seguido por los ministros del gobierno (Gracia y Justicia y Guerra), ademâ”śĂ­s de varios otros marqueses, generales y condes. Las crâ”śâ”‚nicas informan que antes de la procesiâ”śâ”‚n las nubes descargaron una fuerte tormenta que con naturalidad convirtiâ”śâ”‚ las terrosas calles del recorrido, como es el caso de la de Alfonso I, en simpâ”śĂ­ticos barrizales.', 1908, 1908, 1908, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65540700, -0.87993600, '0101000020E61000007A56D28A6F28ECBFE4486760E4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52079851856.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52079851856.webp', 'https://www.flickr.com/photos/zaragozaantigua/52079851856/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24245, 'Calle de Alfonso I 1947', 'Imagen capturada en la calle Alfonso I, a la altura del nâ”¬â•‘ 28, frente al callejâ”śâ”‚n de las Once Esquinas, donde tenâ”śÂˇa su estudio el "pintor-fotâ”śâ”‚grafo" navarro â”śĂĽngel Hilario Garcâ”śÂˇa de Jalâ”śâ”‚n, cuya denominaciâ”śâ”‚n artâ”śÂˇstica era la que figura en el cartel anunciador: Jalâ”śâ”‚n â”śĂĽngel. Aparcado tranquilamente en la calle, un Peugeot 202, y delante, posado de tres elegantes seâ”śâ–’oras. Fuente visual: www.todocoleccion.net/', 1947, 1947, 1947, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.65523200, -0.87996700, '0101000020E61000003BE5D18DB028ECBF76A565A4DED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30638539700.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30638539700.webp', 'https://www.flickr.com/photos/zaragozaantigua/30638539700/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24400, 'San Cayetano 1899', 'Desde las alturas del antiguo palacio de Guara, en la calle de la Montera, un vistazo en direcciâ”śâ”‚n noroeste muestra los tejados del barrio de San Felipe, y la câ”śâ•‘pula y torrecillas de la iglesia de Santa Isabel de Portugal, o de San Cayetano, denominaciâ”śâ”‚n que en la â”śÂ®poca de la imagen (y parece ser que todavâ”śÂˇa) era considerada "vulgar" o asâ”śÂˇ llamada por el "vulgo", si bien era esa la histâ”śâ”‚rica denominaciâ”śâ”‚n de la casa, convento e iglesia de los padres clâ”śÂ®rigos regulares de la providencia, o religiosos teatinos, sus regentes. Fuente visual: Francisco Gâ”śâ”‚rriz, Archivo Municipal de Zaragoza', 1899, 1899, 1899, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65553400, -0.88188900, '0101000020E6100000F777B6476F38ECBF42B5C189E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28406008944.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28406008944.webp', 'https://www.flickr.com/photos/zaragozaantigua/28406008944/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24479, 'Imprenta Berdejo Casaâ”śâ–’al 1925', 'Taller de la "Imprenta de Arte Berdejo Casaâ”śâ–’al", en su ubicaciâ”śâ”‚n de la calle Loscos 7 (antigua Jazmâ”śÂˇn). La captura se ha realizado con motivo de la tirada en prensa del nâ”śâ•‘mero 1 de la revista "Aragâ”śâ”‚n", â”śâ”‚rgano de expresiâ”śâ”‚n del "Sindicato de Iniciativa y Propaganda de Aragâ”śâ”‚n" (SIPA). En el colectivo posado, junto al personal del taller, el secretario del SIPA, Eduardo Cativiela y Pâ”śÂ®rez, que sostiene un ejemplar de la revista. y junto a â”śÂ®l, Eduardo Berdejo Casaâ”śâ–’al, editor de la revista, y propietario de la imprenta. Fuente: Foto Larraz, amablemente proporcionada por Mariano Lacruz Pâ”śÂ®rez.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65556900, -0.88063200, '0101000020E61000004DF4F928232EECBFBEA25BAFE9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22528904220.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22528904220.webp', 'https://www.flickr.com/photos/zaragozaantigua/22528904220/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25070, 'Camarada Fleta 1936', 'â”śĂĽngel Jalâ”śâ”‚n (â”śĂĽngel Hilario Garcâ”śÂˇa de Jalâ”śâ”‚n Hueto), Diputaciâ”śâ”‚n de Zaragoza, agosto 1936. Retrato de Miguel Burro Fleta. Imagen del tenor Fleta habilitado con el uniforme de la Falange Espaâ”śâ–’ola de las JONS (Juntas de Ofensiva Nacional-Sindicalista), capturado de tal traza en el Estudio fotogrâ”śĂ­fico de â”śĂĽngel Jalâ”śâ”‚n (Alfonso I, 28) cuando ya no habâ”śÂˇa rojos en la costa. Falleciâ”śâ”‚ apenas dos aâ”śâ–’os despuâ”śÂ®s, y en su homenaje, la nueva, leal y digital corporaciâ”śâ”‚n municipal cambiâ”śâ”‚ de nombre a la calle Fletas, por "Avenida del Tenor Fleta". Fuente: web.dpz.es/arscatalogi.es/foto.asp?index=2851', 1936, 1936, 1936, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65497800, -0.88015400, '0101000020E6100000D731AEB8382AECBFBCCCB051D6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15696653438.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15696653438.webp', 'https://www.flickr.com/photos/zaragozaantigua/15696653438/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25895, 'Calle del Olmo, c. 1968', 'Pintura centrada en el cruce de las calles del Olmo, desde donde el autor ha capturado la escena, y del Temple, donde al fondo destaca la portalada de acceso al nâ”śâ•‘mero 14 de esa calle, una vivienda posiblemente del siglo XVII construida sobre el solar de una parte del gran complejo monâ”śĂ­stico de la Orden del Temple que ocupâ”śâ”‚ toda esa manzana.y que da nombre a esa calle. A la derecha, vista parcial del antiguo inmueble del nâ”¬â•‘ 11 de la calle del Temple, posteriormente derribado junto con sus vecinas de los nâ”śâ•‘meros 13 y 15 y que a finales de los aâ”śâ–’os 80 del pasado siglo XX su solar conformâ”śâ”‚ un singular espacio poblado de bancos de sentarse y arbolitos, un antecedente al desarrollo, veinte aâ”śâ–’os despuâ”śÂ®s, del proyecto "Estonoesunsolar" y que desde principios de este siglo XXI fue objeto de un desarrollo edilicio que conformâ”śâ”‚ el moderno inmueble del actual nâ”¬â•‘ 18 de la calle del Olmo.', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65553500, -0.88191000, '0101000020E6100000D47D00529B38ECBF12312592E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53205391874.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53205391874.webp', 'https://www.flickr.com/photos/zaragozaantigua/53205391874/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20887, 'Fundaciâ”śâ”‚n de Caesaraugusta', 'Emilio Gil Murillo, "Origen y fundaciâ”śâ”‚n de Zaragoza ", 1896. Ayuntamiento de Zaragoza. La imagen representa idealizado el rito romano de fundaciâ”śâ”‚n de la ciudad, en el 14 antes de la Era. Antes de iniciarlo, el augur consultâ”śâ”‚ los auspicios para asegurarse, mediante signos visibles, de que los dioses no se oponâ”śÂˇan al establecimiento de la ciudad en el lugar escogido. Los dioses no dijeron ni pâ”śÂˇo. Entonces, revestido con una toga dispuesta a la antigua usanza, cogiâ”śâ”‚ las estevas de un arado de bronce, tirado por una ternera y un toro, y trazâ”śâ”‚ un surco alrededor de la futura urbe, siguiendo la misma lâ”śÂˇnea a lo largo de la cual habrâ”śÂˇa de levantarse el muro delimitador. En el transcurso de la ceremonia, se procuraba que toda la tierra levantada por la reja cayese al interior del recinto. Tras â”śÂ®l, los asistentes recogâ”śÂˇan los terrones que a veces saltaban fuera del perâ”śÂˇmetro y los volvâ”śÂˇan a echar donde el rito establecâ”śÂˇa. Al llegar al sitio previsto para las 4 puertas principales, se levantaba el arado con el fin de dejar un espacio libre de toda consagraciâ”śâ”‚n. Cuando el oficiante alcanzâ”śâ”‚ el punto de partida, la ciudad quedâ”śâ”‚ virtualmente fundada.', NULL, NULL, NULL, NULL, 'CASCO HISTâ”śĂ´RICO', 41.65210400, -0.87346600, '0101000020E6100000BB5F05F86EF3EBBF9FCBD42478D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14753929599.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14753929599.webp', 'https://www.flickr.com/photos/zaragozaantigua/14753929599/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20892, 'Domus Calle Heroâ”śÂˇsmo siglo I', 'En 1991 se documentâ”śâ”‚, en el solar de la calle Heroâ”śÂˇsmo 5 y 7 con Aâ”śâ–’â”śâ”‚n (en la imagen, a la derecha) de Zaragoza, una domus romana del siglo I, extramuros de la colonia. Fuente: Zaragoza. Prehistoria y arqueologâ”śÂˇa, Ayuntamiento de Zaragoza, 1991.', 50, NULL, 99, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65117300, -0.87349900, '0101000020E6100000AAD6C22CB4F3EBBFE48409A359D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18564315843.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18564315843.webp', 'https://www.flickr.com/photos/zaragozaantigua/18564315843/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20893, 'â”śĂĽnforas ca. 20', 'Campo de â”śĂ­nforas romano, enterradas hacia el aâ”śâ–’o 20 despuâ”śÂ®s de la Era, como drenaje o câ”śĂ­mara de aire para evitar humedades en las casas procedentes de las crecidas del râ”śÂˇo Ebro. En mayo de 2003 se descubriâ”śâ”‚ este conjunto de casi un millar de â”śĂ­nforas puestas hacia abajo, en el solar de la plaza de las Tenerâ”śÂˇas 9 de Zaragoza. Fuente visual: www.facebook.com/photo.php?fbid=1234779646549079&set=...', NULL, NULL, NULL, NULL, 'CASCO HISTâ”śĂ´RICO', 41.65292800, -0.87130000, '0101000020E61000005227A089B0E1EBBF44520B2593D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19386927608.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19386927608.webp', 'https://www.flickr.com/photos/zaragozaantigua/19386927608/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20896, 'Plaza Asso 1991', 'Tareas de recuperaciâ”śâ”‚n de un tramo de cloaca romana, descubierta en 1990 en la plaza Asso de Zaragoza. Al fondo, la calle Martâ”śÂˇn Carrillo y la torre de la iglesia de la Magdalena. Fuente: Zaragoza. Prehistoria y arqueologâ”śÂˇa, Ayuntamiento de Zaragoza, 1991.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”śĂ´RICO', 41.65308900, -0.87399300, '0101000020E61000008CDAFD2AC0F7EBBF4D309C6B98D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23648332264.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23648332264.webp', 'https://www.flickr.com/photos/zaragozaantigua/23648332264/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20898, 'Plaza Magdalena 1990', 'En 1990 se hallâ”śâ”‚ un tramo de losas de la calzada romana del Decumano Mâ”śĂ­ximo, que sirviâ”śâ”‚ para confirmar que la calle Mayor se hallaba sobre â”śÂ®ste. En la foto, el comienzo de la calle Mayor, a la altura de la plaza de la Magdalena, con la iglesia homâ”śâ”‚nima arriba a la izquierda. Fuente: Las cloacas de Cesaraugusta, IFC, 2013.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”śĂ´RICO', 41.65223900, -0.87360700, '0101000020E610000042D0D1AA96F4EBBF7F164B917CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24194356511.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24194356511.webp', 'https://www.flickr.com/photos/zaragozaantigua/24194356511/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20922, 'Colegio del Padre Eterno 1778', 'Plano del terreno de las Escuelas Pâ”śâ•‘blicas y del Colegio del Padre Eterno, Joseph Arberuela, Zaragoza, 19 de diciembre de 1778. El colegio del Padre Eterno, de los jesuitas, albergâ”śâ”‚ desde 1788 las primeras instalaciones del Seminario Conciliar de San Valero y San Braulio. Se encontraba en el actual Coso 127, esquina con la calle de San Lorenzo. Fuente: Archivo General de Simancas, Ministerio de Cultura de Espaâ”śâ–’a.', 1778, 1778, 1778, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65158800, -0.87402800, '0101000020E6100000A839799109F8EBBFA73B4F3C67D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20225243629.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20225243629.webp', 'https://www.flickr.com/photos/zaragozaantigua/20225243629/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20941, 'Convento de San Agustâ”śÂˇn 1563', 'El convento de San Agustâ”śÂˇn tal y como aparece en la vista de Zaragoza realizada en 1663 por el dibujante Anton van der Wyngaerde/Antonio de las Viâ”śâ–’as.', 1563, 1563, 1563, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65140000, -0.87079400, '0101000020E61000005FB2F1608BDDEBBFA54E401361D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54387299485.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54387299485.webp', 'https://www.flickr.com/photos/zaragozaantigua/54387299485/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20956, 'Coso Bajo 1808', '"Ruinas del Seminario vistas por la noche: cuando los patriotas, que no podâ”śÂˇan asistir a la defensa de las puertas, a la luz de sus linternas y de los incendios, causados por las bombas, buscaban entre los escombros a los muertos para darles sepultura". Serie Ruinas de Zaragoza, de Juan Gâ”śĂ­lvez (dibujo) y Fernando Brambila (grabado), Câ”śĂ­diz, 1812. El conjunto de edificios del Seminario Mayor de Zaragoza se extendâ”śÂˇa por el Coso Bajo en direcciâ”śâ”‚n al Ebro, mâ”śĂ­s allâ”śĂ­ de la calle de San Jorge. En la acera de la gran mole semiderruida, mâ”śĂ­s al fondo, se ve la entrada a la plaza de la Magdalena. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65158800, -0.87402800, '0101000020E6100000A839799109F8EBBFA73B4F3C67D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15267099411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15267099411.webp', 'https://www.flickr.com/photos/zaragozaantigua/15267099411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20967, 'Universidad 1814', '"La Academia de Zaragoza al regreso de Fernando VII". Medalla realizada por Antonio Martâ”śÂˇnez y acuâ”śâ–’ada por la Universidad de Zaragoza cuando se reanudaron las clases tras la retirada de los franceses en 1814. En 1913 se terminâ”śâ”‚ una reforma que modificâ”śâ”‚ su aspecto, a cargo de Ricardo Magdalena. Al fondo a la derecha, personificaciâ”śâ”‚n del râ”śÂˇo Ebro. Fuente: Museo del Prado.', 1814, 1814, 1814, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65222400, -0.87323600, '0101000020E61000004D13B69F8CF1EBBF49D576137CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18985824170.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18985824170.webp', 'https://www.flickr.com/photos/zaragozaantigua/18985824170/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22670, 'Feria de Muestras 1976', 'Imagen en altura de la Feria de Muestras, y su caracterâ”śÂˇstico mirador acristalado, desde un punto de vista contrario a la inmensa mayorâ”śÂˇa de las capturas realizadas de la zona: hacia el noreste, mirando hacia la ciudad. Este pequeâ”śâ–’o detalle permite observar el agujero, a la derecha, donde antes estuvieron los talleres de la Editorial Luis Vives, y ahora se estaba gestando la macizada y compacta manzana de bloques habitacionales que la iba a sustituir. Eso permite, excepcionalmente, visual directa de la calle Luis Vives y el desemboque a ella de Andrâ”śÂ®s Piquer, Teresa de Jesâ”śâ•‘s, y Mariano Supervâ”śÂˇa, con el Grupo "Francisco Caballero" y restos supervivientes de antiguos hotelitos de la zona del Ensanche de Miralbueno, al poco derribados y sustituidos por cosas mâ”śĂ­s modernas y apropiadas. Fuente visual: Gerardo Sancho Ramo (Archivo Pâ”śâ•‘blico Municipal).', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63744800, -0.89883900, '0101000020E6100000ABD1AB014AC3ECBF477364E597D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23539505284.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23539505284.webp', 'https://www.flickr.com/photos/zaragozaantigua/23539505284/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21009, 'Arco de Valencia 1867', 'Imagen del antiguo arco de Valencia poco antes de su derribo realizado entre el 20 de enero y el 15 de febrero de ese aâ”śâ–’o, al objeto de despejar las casas de los nâ”śâ•‘meros 71, 73, 75 y 77 del Coso (a la derecha) que afeaban el ingreso a la Universidad Literaria, y parte de la casa del nâ”¬â•‘ 96 de la calle Mayor (a la izquierda). El derribo del arco se hizo hilada a hilada de piedra, y el de las casas piso a piso, sin permitirse "derribos en grandes masas". Tal vez por ello llamaron la atenciâ”śâ”‚n buen nâ”śâ•‘mero de piedras que lucâ”śÂˇan caracteres latinos, algunas de las cuales sobrevivieron al reaprovechamiento de los materiales del derribo, que aunque se realizâ”śâ”‚ dentro de los lâ”śÂˇmites de tiempo establecidos, dejâ”śâ”‚ durante varios meses un "rastro" de grandes piedras "y no menores excabaciones" o cisternas ante la despejada fachada de la Universidad Literaria. La captura de esta fotografâ”śÂˇa se ha realizado desde el arranque de la vecina calle de Palomar. En primer tâ”śÂ®rmino, tramo del Coso que hasta ese momento era denominado "plaza de la Magdalena", caracterizado por las botigas comerciales y puestos ambulantes allâ”śÂˇ establecidos. Al fondo, tras el arco, vista de la barroca portada de la iglesia parroquial de Santa Marâ”śÂˇa Magdalena, cuya torre despunta a la izquierda. Tras el derribo del arco y las casas, una nueva plaza de la Magdalena surgiâ”śâ”‚ entonces en su actual ubicaciâ”śâ”‚n.', 1867, 1867, 1867, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65210700, -0.87336500, '0101000020E6100000C2120F289BF2EBBF103FFF3D78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15092142102.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15092142102.webp', 'https://www.flickr.com/photos/zaragozaantigua/15092142102/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21010, 'Puerta de Valencia 1867', 'Puerta de Valencia vista desde la puerta de la iglesia de la Magdalena, justo antes de ser demolida ese aâ”śâ–’o, para dar a la plaza de la Magdalena algo mâ”śĂ­s de desahogo y dejar al descubierto el frontispicio de la Universidad. Al fondo, el Coso bajo y la calle de Palomar. Fuente visual: Santos â”śĂĽlvarez y Serra, en AMZ.', 1867, 1867, 1867, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65201200, -0.87320400, '0101000020E61000007590D78349F1EBBFBE4C142175D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15093846679.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15093846679.webp', 'https://www.flickr.com/photos/zaragozaantigua/15093846679/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21097, 'Paraninfo de la Universidad 1880', 'Sesiâ”śâ”‚n inaugural del Congreso Filoxâ”śÂ®rico celebrado en 1880 en el paraninfo de la Universidad de Zaragoza en la plaza de la Magdalena. No confundir con el actual edificio sito en la plaza de Paraâ”śÂˇso, construido posteriormente. La plaga vitivinâ”śÂˇcola de la filoxera fue detectada en Francia en 1865. Las 952.000 Ha de viâ”śâ–’edo que tenâ”śÂˇa en cultivo la provincia de Zaragoza quedaron reducidas, tras la plaga, a 12.275. El congreso cuya inauguraciâ”śâ”‚n reproduce el croquis se celebrâ”śâ”‚ para intentar frenar la catâ”śĂ­strofe agrâ”śÂˇcola que se preveâ”śÂˇa. El dibujo, de Bernardo Rico y Ortega, basado en un croquis apuntado por "D. Lascun", posiblemente Dionisio Lasuâ”śÂ®n. Fuente visual: "La Ilustraciâ”śâ”‚n Espaâ”śâ–’ola y Americana".', 1880, 1880, 1880, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65221400, -0.87327900, '0101000020E61000001F1329CDE6F1EBBF26FF93BF7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14856449014.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14856449014.webp', 'https://www.flickr.com/photos/zaragozaantigua/14856449014/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21111, 'Pl. de la Magdalena 1889', '"Saragosse. â”śĂ«glise de la Magdeleine". Fuente: J. Lâ”śÂ®vy et Cie, en "Zaragoza en la mirada ajena", Cortes de Aragâ”śâ”‚n, 2012.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65236800, -0.87371300, '0101000020E6100000ACE122F774F5EBBF7D7A6CCB80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22736718751.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22736718751.webp', 'https://www.flickr.com/photos/zaragozaantigua/22736718751/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21135, 'Plaza de la Magdalena c.1880', 'Luminosa imagen capturada desde la altura del inmueble del nâ”¬â•‘ 188 del Coso Bajo y centrada en la plaza de la Magdalena, donde destaca la torre y la puerta de ingreso a la iglesia parroquial de Santa Marâ”śÂˇa Magdalena. A la izquierda, desemboque de la calle Mayor en la plaza con vista de las â”śâ•‘ltimas casas del lado de los pares tras la calle de Pelegrin. A la derecha, esquina del final de la calle de Martâ”śÂˇn Carrillo con el arranque de la calle de la Universidad, donde destaca la antigua Casa Tejada, en cuyos bajos se abre la puerta de un comercio de ultramarinos donde tambiâ”śÂ®n se despachaba carbâ”śâ”‚n de haya. A continuaciâ”śâ”‚n, leve vista de la fachada de la Universidad Literaria. Como el cielo de la fotografâ”śÂˇa ha sido "editado" en origen, ha desaparecido la vista de la inacabada torre de Santiago y de la câ”śâ•‘pula central del templo del Pilar, que deberâ”śÂˇan despuntar sobre Casa Tejada, asâ”śÂˇ como la torre de la Seo. Hemos volteado horizontalmente la fotografâ”śÂˇa tal y como aparece en el AHPZ, para darle sentido y sensibilidad.', 1880, 1880, 1880, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65224000, -0.87350900, '0101000020E61000008D5F7825C9F3EBBF4F92AE997CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52230624372.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52230624372.webp', 'https://www.flickr.com/photos/zaragozaantigua/52230624372/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21145, 'Cuartel de Caballos Sementales 1899', 'â”śĂĽlbum del Ministerio de la Guerra. Ministerio de Defensa de Espaâ”śâ–’a. 1899. Por Real orden de 17 de agosto de 1885 se creâ”śâ”‚ en Zaragoza una secciâ”śâ”‚n de sementales al objeto de la mejora de la cabaâ”śâ–’a de Aragâ”śâ”‚n, con 85 sementales percherones y boloâ”śâ–’eses. El 22 de marzo de 1905 se crea el Quinto Depâ”śâ”‚sito de Caballos Sementales. Su ubicaciâ”śâ”‚n, terrenos municipales de la Calle del Asalto. Allâ”śÂˇ estuvieron hasta el 18 de julio de 1989. En la imagen, carruaje con tres sementales ante la puerta del Depâ”śâ”‚sito. Detrâ”śĂ­s del muro, al fondo, la calle Asalto y su confluencia con Alonso V.', 1899, 1899, 1899, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65126900, -0.86970100, '0101000020E6100000478D093197D4EBBF06F357C85CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14991847139.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14991847139.webp', 'https://www.flickr.com/photos/zaragozaantigua/14991847139/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21157, 'Calle de la Universidad 1898', 'Instituto Universitario Provincial de Zaragoza, 1898. En 1847 se separaron las docencias de los institutos y las universidades, creâ”śĂ­ndose este centro en el edificio de la Universidad Literaria de La Magdalena. Su entrada estaba en la calle Universidad. En 1933 fue trasladado al edificio del suprimido Colegio del Salvador, y se le dio el nombre de "Instituto Nacional de Segunda Enseâ”śâ–’anza Goya". Despuâ”śÂ®s del 18 de julio de 1936, fue trasladado a la Escuela de Artes, primero, y luego regresâ”śâ”‚ a la Magdalena. Cuando se inaugurâ”śâ”‚ el edificio del nuevo Instituto "Goya" junto al Huerva y la avenida Goya, se trasladâ”śâ”‚ allâ”śÂˇ definitivamente en 1959. Fuente visual: www.facebook.com/photo.php?fbid=10204723386338133&set...', 1898, 1898, 1898, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65304800, -0.87297400, '0101000020E61000000744882B67EFEBBFEE5BAD1397D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19510424782.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19510424782.webp', 'https://www.flickr.com/photos/zaragozaantigua/19510424782/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21162, 'Calle Mayor 1893', '"Fragmento de la torre e iglesia de Santa Magdalena". Este dibujo, basado en una fotografâ”śÂˇa, captura en altura la torre y parcialmente la iglesia con la calle Mayor a sus pies, estrecha como originalmente era. Por una de esas casualidades ocasionales, el dibujante se ha centrado en la fâ”śĂ­brica de la torre tal y como fue trabajada por los alarifes medievales que la levantaron, y ha prescindido del remate barroco aâ”śâ–’adido posteriormente. Fuente: "La Ilustraciâ”śâ”‚n Ibâ”śÂ®rica", Barcelona.', 1893, 1893, 1893, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65236800, -0.87371300, '0101000020E6100000ACE122F774F5EBBF7D7A6CCB80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20497312783.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20497312783.webp', 'https://www.flickr.com/photos/zaragozaantigua/20497312783/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21205, 'Cuartel de San Agustâ”śÂˇn 1907', 'Postal. "Colecciâ”śâ”‚n Patria y Fe nâ”śâ•‘m. 8, Zaragoza 1908 - Centenario de los Sitios", 1907. "El convento de San Agustâ”śÂˇn, donde hoy se encuentran las Factorâ”śÂˇas militares, hâ”śĂ­llase situado en las afueras, en un punto muy apetecido por los franceses cuando intentaron entrar en Zaragoza por la plaza de la Magdalena; durante el segundo sitio, el uno de febrero, se apoderaron de â”śÂ®l las tropas de Napoleâ”śâ”‚n." Puerta de entrada al cuartel de San Agustâ”śÂˇn, antes convento. Lo que parece un guardia espera sentado tranquilo. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65071100, -0.87039700, '0101000020E61000001B2B31CF4ADAEBBFE012807F4AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14750296987.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14750296987.webp', 'https://www.flickr.com/photos/zaragozaantigua/14750296987/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21246, 'Pl. de la Magdalena 1907', 'Postal. "Colecciâ”śâ”‚n Patria y Fe nâ”śâ•‘m. 27, Zaragoza 1908 - Centenario de los Sitios", 1907. "Uno de los edificios mâ”śĂ­s antiguos de Zaragoza; muy castigado por hallarse detrâ”śĂ­s de la puerta de Valencia, frente a la cual los franceses colocaron el 7 de febrero de 1809, un caâ”śâ–’â”śâ”‚n de a 24, con el que abrieron una gran brecha. En sus cisternas fueron sepultadas numerosas vâ”śÂˇctimas." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65236800, -0.87371300, '0101000020E6100000ACE122F774F5EBBF7D7A6CCB80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20150686613.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20150686613.webp', 'https://www.flickr.com/photos/zaragozaantigua/20150686613/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21247, 'Ruinas del Hospitalito 1907', 'Postal. "Colecciâ”śâ”‚n Patria y Fe nâ”śâ•‘m. 29, Zaragoza 1908 - Centenario de los Sitios", 1907. "Efecto de las bombas enemigas en la capilla de este benâ”śÂ®fico establecimiento conocido con el nombre de Hospitalito de la Magdalena. Despuâ”śÂ®s de la explosiâ”śâ”‚n del almacâ”śÂ®n de la pâ”śâ”‚lvora (27junio), en el Hospitalito fueron custodiados los enseres de las casas arruinadas, y en su cementerio enterrâ”śĂ­ronse las vâ”śÂˇctimas." El Hospitalito u "Hospitalico de Nuestra Seâ”śâ–’ora de la Misericordia u Hospital de Niâ”śâ–’os y Niâ”śâ–’as Huâ”śÂ®rfanos de la ciudad de Zaragoza" fue fundado en 1543 y arruinado en 1808. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65172600, -0.87326300, '0101000020E6100000B3D1393FC5F1EBBFF8F9EFC16BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20150826383.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20150826383.webp', 'https://www.flickr.com/photos/zaragozaantigua/20150826383/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21256, 'Calle Heroâ”śÂˇsmo 1907', 'Postal. "Colecciâ”śâ”‚n Patria y Fe nâ”śâ•‘m. 22, Zaragoza 1908 - Centenario de los Sitios", 1907. "En esta calle, que viene a salir al Coso en las inmediaciones de la plaza de la Magdalena, riâ”śâ–’â”śÂ®ronse luchas formidables, cuerpo a cuerpo, entre sitiadores y sitiados. Minâ”śĂ­ronse las casas, que fueron asaltadas una a una, y reconquistadas igualmente a cuenta de sangre y vidas." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65085200, -0.87403600, '0101000020E61000005EDA70581AF8EBBFA2444B1E4FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20582520218.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20582520218.webp', 'https://www.flickr.com/photos/zaragozaantigua/20582520218/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21261, 'Calle de las Tenerâ”śÂˇas 1907', 'Postal. "Colecciâ”śâ”‚n Patria y Fe nâ”śâ•‘m. 39, Zaragoza 1908 - Centenario de los Sitios", 1907. "Llamado asâ”śÂˇ por haberse destinado alguna de sus casas a la fabricaciâ”śâ”‚n de curtidos. En su lugar hallâ”śĂ­base antes emplazada la puerta del Sol. A este arrabal pertenecâ”śÂˇa el llamado corral de Marigaita desde donde se dominaba gran parte de la ribera del Ebro, por lo cual se construyeron allâ”śÂˇ muy importantes baterâ”śÂˇas que riâ”śâ–’eron fieras luchas." Vista de la actual calle de Alonso V en su confluencia con la plaza de las Tenerâ”śÂˇas. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65316900, -0.87164300, '0101000020E6100000CA3159DC7FE4EBBF69E1B20A9BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20763354052.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20763354052.webp', 'https://www.flickr.com/photos/zaragozaantigua/20763354052/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21262, 'Calle del Pozo 1907', 'Postal. "Colecciâ”śâ”‚n Patria y Fe nâ”śâ•‘m. 2, Zaragoza 1908 - Centenario de los Sitios", 1907. "Por el buen punto de vista que ofrecâ”śÂˇa esta casa, cuya entrada estâ”śĂ­ por la calle de Palomar, las balas enemigas hicieron blanco en ella frecuentemente. Durante el segundo sitio los franceses intentaron penetrar en Zaragoza por este punto pero, sin pasar de la plaza de la Magdalena, siempre fueron enâ”śÂ®rgicamente rechazados." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65125200, -0.87232000, '0101000020E6100000EEB1F4A10BEAEBBF30BABC395CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20767321535.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20767321535.webp', 'https://www.flickr.com/photos/zaragozaantigua/20767321535/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21380, 'Coso Bajo c.1910', 'Anselmo Marâ”śÂˇa Coyne, Diputaciâ”śâ”‚n de Zaragoza, ca. 1910 Imagen de tremenda carretada de aguateros en el Coso Bajo, a la altura de la plaza de la Magdalena. A la izquierda, la Universidad Literaria de la Magdalena, antes de su reforma por Ricardo Magdalena. Fuente: web.dpz.es/arscatalogi.es/foto.asp?index=2818', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”śĂ´RICO', 41.65201200, -0.87320400, '0101000020E61000007590D78349F1EBBFBE4C142175D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15854328636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15854328636.webp', 'https://www.flickr.com/photos/zaragozaantigua/15854328636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
